import{_ as o,c as n,o as a,a5 as t}from"./chunks/framework.CgT1UzWm.js";const u=JSON.parse('{"title":"Changelog v3.4.6 (2025-01-21)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/changelog/v3.4.6.md","filePath":"guide/changelog/v3.4.6.md"}'),r={name:"guide/changelog/v3.4.6.md"};function i(d,e,c,l,s,p){return a(),n("div",null,e[0]||(e[0]=[t('<h1 id="changelog-v3-4-6-2025-01-21" tabindex="-1">Changelog v3.4.6 (2025-01-21) <a class="header-anchor" href="#changelog-v3-4-6-2025-01-21" aria-label="Permalink to &quot;Changelog v3.4.6 (2025-01-21)&quot;">​</a></h1><h2 id="version-3-4-6-2025-01-21" tabindex="-1">Version <a href="https://github.com/NpgsqlRest/NpgsqlRest/tree/3.4.6" target="_blank" rel="noreferrer">3.4.6</a> (2025-01-21) <a class="header-anchor" href="#version-3-4-6-2025-01-21" aria-label="Permalink to &quot;Version [3.4.6](https://github.com/NpgsqlRest/NpgsqlRest/tree/3.4.6) (2025-01-21)&quot;">​</a></h2><p><a href="https://github.com/NpgsqlRest/NpgsqlRest/compare/3.4.5...3.4.6" target="_blank" rel="noreferrer">Full Changelog</a></p><h3 id="endpoint-execution-performance-optimizations" tabindex="-1">Endpoint Execution Performance Optimizations <a class="header-anchor" href="#endpoint-execution-performance-optimizations" aria-label="Permalink to &quot;Endpoint Execution Performance Optimizations&quot;">​</a></h3><p>Reduced memory allocations and CPU overhead in the hot path of endpoint execution through several optimizations:</p><p><strong>StringBuilder Pooling</strong></p><p>Added a thread-safe <code>StringBuilderPool</code> to reuse <code>StringBuilder</code> instances across requests instead of allocating new ones:</p><ul><li><code>cmdLog</code> - command logging</li><li><code>cacheKeys</code> - cache key building</li><li><code>rowBuilder</code> - response row building</li><li><code>compositeFieldBuffer</code> - nested JSON composite handling</li><li><code>commandTextBuilder</code> - SQL command text building</li></ul><p>The pool maintains up to 64 instances with lock-free rent/return operations.</p><p><strong>Avoid Query String Dictionary Allocation</strong></p><p>Changed from <code>context.Request.Query.ToDictionary()</code> to using <code>IQueryCollection</code> directly, eliminating a dictionary allocation on every request. The <code>IQueryCollection</code> interface already provides <code>TryGetValue()</code>, <code>Count</code>, and <code>ContainsKey()</code> methods.</p><p><strong>StringBuilder for Command Text Building</strong></p><p>Replaced ~18 <code>string.Concat(commandText, ...)</code> calls with <code>StringBuilder.Append()</code> operations, reducing intermediate string allocations when building SQL commands for non-formattable routines.</p><p><strong>HashSet for Path Parameter Lookup</strong></p><p>Added <code>FindMatchingPathParameter()</code> method with lazy-initialized <code>HashSet&lt;string&gt;</code> for O(1) case-insensitive lookups instead of O(n) array iteration when matching path parameters.</p><hr><h3 id="comprehensive-cancellationtoken-propagation" tabindex="-1">Comprehensive CancellationToken Propagation <a class="header-anchor" href="#comprehensive-cancellationtoken-propagation" aria-label="Permalink to &quot;Comprehensive CancellationToken Propagation&quot;">​</a></h3><p>Improved cancellation token propagation throughout the entire request pipeline. The <code>CancellationToken</code> parameter is now properly passed to all async operations, enabling proper request cancellation and resource cleanup when clients disconnect or requests are aborted.</p><p><strong>Changes:</strong></p><ul><li><p><strong>NpgsqlRestEndpoint</strong>: Fixed missing cancellation token propagation to <code>ReadToEndAsync</code>, <code>ReadAsync</code>, <code>WriteAsync</code>, <code>FlushAsync</code>, <code>BeginTransactionAsync</code>, <code>CommitAsync</code>, and helper methods (<code>PrepareCommand</code>, <code>OpenConnectionAsync</code>, <code>ValidateParametersAsync</code>, <code>ReturnErrorAsync</code>).</p></li><li><p><strong>Auth Handlers</strong>: Added <code>CancellationToken</code> parameter to <code>BasicAuthHandler.HandleAsync</code>, <code>LoginHandler.HandleAsync</code>, and <code>LogoutHandler.HandleAsync</code>. All database operations and response writes now respect cancellation.</p></li><li><p><strong>Upload Handlers</strong>: Updated <code>IUploadHandler.UploadAsync</code> interface and all implementations (<code>DefaultUploadHandler</code>, <code>FileSystemUploadHandler</code>, <code>LargeObjectUploadHandler</code>, <code>CsvUploadHandler</code>, <code>ExcelUploadHandler</code>) to accept and propagate cancellation tokens to file I/O and database operations.</p></li><li><p><strong>Proxy Handler</strong>: Added <code>CancellationToken</code> parameter to <code>ProxyRequestHandler.WriteResponseAsync</code> for cancellable response body writes.</p></li></ul><p><strong>Benefits:</strong></p><ul><li>Immediate cleanup when HTTP clients disconnect mid-request</li><li>Proper cancellation of long-running database queries</li><li>Reduced resource consumption from abandoned requests</li><li>Better handling of upload/download operations that can be cancelled</li><li><strong>Prevents request storms</strong>: When users repeatedly refresh the browser during slow endpoint execution, each refresh creates a new request while the previous one continues running. Without proper cancellation token propagation, these abandoned requests continue executing database queries, potentially choking the database. With this fix, abandoned requests are properly cancelled, freeing up database connections immediately.</li></ul><hr>',23)]))}const h=o(r,[["render",i]]);export{u as __pageData,h as default};
